QUnit.module("$.bsCalendar — Global API",function(){QUnit.test("version is 2.3.4",function(t){t.strictEqual($.bsCalendar.version,"2.3.4")}),QUnit.test("about has expected fields",function(t){const a=$.bsCalendar.about;t.strictEqual(a.version,"2.3.4"),t.strictEqual(a.license,"MIT"),t.ok(a.project.startsWith("https://")),t.ok(a.issues.startsWith("https://"))}),QUnit.test("possibleViews contains all five views",function(t){const a=$.bsCalendar.possibleViews;t.ok(Array.isArray(a)),["day","4day","week","month","year"].forEach(e=>t.ok(a.includes(e),`possibleViews includes "${e}"`))}),QUnit.module("setDefaults / getDefaults",function(t){let a;t.beforeEach(function(){a=$.bsCalendar.getDefaults().locale}),t.afterEach(function(){$.bsCalendar.setDefaults({locale:a})}),QUnit.test("getDefaults returns the DEFAULTS object",function(t){const a=$.bsCalendar.getDefaults();t.strictEqual(typeof a,"object"),t.strictEqual(a.locale,"en-GB"),t.strictEqual(a.startView,"month")}),QUnit.test("setDefaults mutates DEFAULTS",function(t){$.bsCalendar.setDefaults({locale:"de-DE"}),t.strictEqual($.bsCalendar.getDefaults().locale,"de-DE")}),QUnit.test("setDefaults deep-merges nested objects",function(t){const a=$.bsCalendar.getDefaults().hourSlots.end;$.bsCalendar.setDefaults({hourSlots:{start:8}});const e=$.bsCalendar.getDefaults();t.strictEqual(e.hourSlots.start,8,"start changed"),t.strictEqual(e.hourSlots.end,a,"end unchanged"),$.bsCalendar.setDefaults({hourSlots:{start:0}})})}),QUnit.module("Translations",function(){QUnit.test('getTranslations returns English for "en"',function(t){const a=$.bsCalendar.getTranslations("en");t.strictEqual(a.today,"Today"),t.strictEqual(a.month,"Month")}),QUnit.test('getTranslations returns German for "de"',function(t){const a=$.bsCalendar.getTranslations("de");t.strictEqual(a.today,"Heute")}),QUnit.test('getTranslations strips region tag — "de-DE" uses "de"',function(t){const a=$.bsCalendar.getTranslations("de"),e=$.bsCalendar.getTranslations("de-DE");t.deepEqual(a,e)}),QUnit.test("getTranslations falls back to English for unknown locale",function(t){const a=$.bsCalendar.getTranslations("xx");t.strictEqual(a.today,"Today")}),QUnit.test("getTranslation returns single key",function(t){t.strictEqual($.bsCalendar.getTranslation("de","today"),"Heute"),t.strictEqual($.bsCalendar.getTranslation("en","today"),"Today")}),QUnit.test("getTranslation falls back to English for unknown locale",function(t){t.strictEqual($.bsCalendar.getTranslation("xx","today"),"Today")}),QUnit.test("getTranslation returns key itself when key does not exist",function(t){t.strictEqual($.bsCalendar.getTranslation("en","__nonexistent__"),"__nonexistent__")}),QUnit.test("addTranslation registers a new locale",function(t){$.bsCalendar.addTranslation("eo",{today:"Hodiaŭ",day:"Tago","4day":"4 Tagoj",week:"Semajno",month:"Monato",year:"Jaro",search:"Tajpu kaj premu Enter",searchNoResult:"Neniu rendevuo trovita",tasks:"Taskoj",taskPriorityHigh:"Alta",taskPriorityNormal:"Normala",taskPriorityLow:"Malalta",duplicate:"Duobligi"}),t.strictEqual($.bsCalendar.getTranslation("eo","today"),"Hodiaŭ")}),QUnit.test("addTranslation merges with English for missing keys",function(t){$.bsCalendar.addTranslation("eo-custom",{today:"Hodiaŭ"}),t.strictEqual($.bsCalendar.getTranslation("eo-custom","month"),"Month")})})});